@namespace sv_494016ad00ea46c48391ee28b8b4cf4d.Components.Pages.Catalog

<div class="card h-100 product-card @(Product.InStock ? "" : "border-secondary")"
     style="cursor: pointer;"
     @onclick="HandleCardClick">
    <div class="card-img-top bg-light d-flex align-items-center justify-content-center"
         style="height: 180px;"
         role="img"
         aria-label="@Product.Name">
        <span class="text-muted">@Product.Name</span>
    </div>
    <div class="card-body d-flex flex-column">
        <h6 class="card-title text-truncate" title="@Product.Name">@Product.Name</h6>
        <p class="card-text fw-bold text-primary mb-1">@Product.Price.ToString("C")</p>
        <p class="card-text mb-2">
            @for (int i = 1; i <= 5; i++)
            {
                <span class="@(i <= Math.Round(Product.Rating) ? "text-warning" : "text-muted")">★</span>
            }
        </p>
        @if (!Product.InStock)
        {
            <span class="badge bg-secondary mb-2">Out of Stock</span>
        }
        <button class="btn btn-sm @(Product.InStock ? "btn-primary" : "btn-outline-secondary") mt-auto"
                disabled="@(!Product.InStock)"
                @onclick="HandleAddToCart"
                @onclick:stopPropagation="true">
            Add to Cart
        </button>
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public Product Product { get; set; } = default!;

    [Parameter]
    public EventCallback<Product> OnSelected { get; set; }

    [Parameter]
    public EventCallback<Product> OnAddToCart { get; set; }

    private async Task HandleCardClick()
    {
        await OnSelected.InvokeAsync(Product);
    }

    private async Task HandleAddToCart()
    {
        if (Product.InStock)
        {
            await OnAddToCart.InvokeAsync(Product);
        }
    }
}

@namespace sv_494016ad00ea46c48391ee28b8b4cf4d.Components.Pages.Catalog

@if (Products.Count == 0)
{
    <div class="alert alert-info text-center my-4">
        <p class="mb-0">No products found matching your criteria.</p>
    </div>
}
else
{
    <div class="row row-cols-1 row-cols-sm-2 row-cols-lg-3 g-3">
        @foreach (var product in Products)
        {
            <div class="col">
                <ProductCard Product="product"
                             OnSelected="OnProductSelected"
                             OnAddToCart="OnAddToCart" />
            </div>
        }
    </div>
}

@code {
    [Parameter, EditorRequired]
    public List<Product> Products { get; set; } = new();

    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    [Parameter]
    public EventCallback<Product> OnAddToCart { get; set; }
}

@namespace sv_494016ad00ea46c48391ee28b8b4cf4d.Components.Pages.Catalog

<div class="p-3 border rounded bg-white">
    <h5 class="mb-3">Filters</h5>

    <div class="mb-3">
        <label class="form-label fw-semibold">Categories</label>
        @if (Categories.Count == 0)
        {
            <p class="text-muted small">Loading…</p>
        }
        else
        {
            @foreach (var category in Categories)
            {
                <div class="form-check">
                    <input class="form-check-input" type="checkbox" id="@($"cat-{category}")"
                           checked="@selectedCategories.Contains(category)"
                           @onchange="@(e => ToggleCategory(category, (bool)e.Value!))" />
                    <label class="form-check-label" for="@($"cat-{category}")">@category</label>
                </div>
            }
        }
    </div>

    <div class="mb-3">
        <label class="form-label fw-semibold">Price Range</label>
        <div class="d-flex gap-2 align-items-center">
            <input type="number" class="form-control form-control-sm" placeholder="Min"
                   value="@minPrice" @onchange="@(e => minPrice = ParseDecimal(e.Value))" min="0" />
            <span>–</span>
            <input type="number" class="form-control form-control-sm" placeholder="Max"
                   value="@maxPrice" @onchange="@(e => maxPrice = ParseDecimal(e.Value))" min="0" />
        </div>
    </div>

    <div class="mb-3">
        <div class="form-check">
            <input class="form-check-input" type="checkbox" id="inStockOnly"
                   checked="@inStockOnly"
                   @onchange="@(e => inStockOnly = (bool)e.Value!)" />
            <label class="form-check-label" for="inStockOnly">In Stock Only</label>
        </div>
    </div>

    <div class="d-grid gap-2">
        <button class="btn btn-primary btn-sm" @onclick="ApplyFilters">Apply Filters</button>
        <button class="btn btn-outline-secondary btn-sm" @onclick="ClearFilters">Clear Filters</button>
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public List<string> Categories { get; set; } = new();

    [Parameter]
    public EventCallback<ProductFilter> OnFilterApplied { get; set; }

    private HashSet<string> selectedCategories = new();
    private decimal? minPrice;
    private decimal? maxPrice;
    private bool inStockOnly;

    private void ToggleCategory(string category, bool isChecked)
    {
        if (isChecked)
            selectedCategories.Add(category);
        else
            selectedCategories.Remove(category);
    }

    private async Task ApplyFilters()
    {
        var filter = new ProductFilter(
            Categories: selectedCategories.Count > 0 ? selectedCategories.ToList() : null,
            MinPrice: minPrice,
            MaxPrice: maxPrice,
            InStockOnly: inStockOnly
        );
        await OnFilterApplied.InvokeAsync(filter);
    }

    private async Task ClearFilters()
    {
        selectedCategories.Clear();
        minPrice = null;
        maxPrice = null;
        inStockOnly = false;
        await OnFilterApplied.InvokeAsync(new ProductFilter(null, null, null, false));
    }

    private static decimal? ParseDecimal(object? value)
    {
        if (value is null || string.IsNullOrWhiteSpace(value.ToString()))
            return null;
        return decimal.TryParse(value.ToString(), out var result) ? result : null;
    }
}

@namespace sv_494016ad00ea46c48391ee28b8b4cf4d.Components.Pages.Catalog

<div class="d-flex flex-wrap justify-content-between align-items-center mb-3 gap-2">
    <div class="d-flex align-items-center gap-2">
        <label class="form-label mb-0 fw-semibold" for="sortSelect">Sort by:</label>
        <select id="sortSelect" class="form-select form-select-sm" style="width: auto;"
                value="@SortBy" @onchange="HandleSortChanged">
            <option value="price_asc">Price: Low to High</option>
            <option value="price_desc">Price: High to Low</option>
            <option value="name_asc">Name: A-Z</option>
            <option value="rating_desc">Rating: Highest</option>
        </select>
    </div>
    <span class="text-muted small">
        @if (TotalCount > 0)
        {
            var start = (Page - 1) * PageSize + 1;
            var end = Math.Min(Page * PageSize, TotalCount);
            <text>Showing @start–@end of @TotalCount products</text>
        }
    </span>
</div>

@code {
    [Parameter] public string SortBy { get; set; } = "price_asc";
    [Parameter] public int Page { get; set; }
    [Parameter] public int PageSize { get; set; }
    [Parameter] public int TotalCount { get; set; }
    [Parameter] public EventCallback<string> OnSortChanged { get; set; }

    private async Task HandleSortChanged(ChangeEventArgs e)
    {
        await OnSortChanged.InvokeAsync(e.Value?.ToString() ?? "price_asc");
    }
}

@namespace sv_494016ad00ea46c48391ee28b8b4cf4d.Components.Pages.Catalog

@if (TotalPages > 1)
{
    <nav aria-label="Product pagination" class="mt-4">
        <ul class="pagination justify-content-center mb-0">
            <li class="page-item @(CurrentPage <= 1 ? "disabled" : "")">
                <button class="page-link" @onclick="@(() => GoToPage(CurrentPage - 1))" disabled="@(CurrentPage <= 1)">
                    Previous
                </button>
            </li>
            @foreach (var page in GetPageNumbers())
            {
                <li class="page-item @(page == CurrentPage ? "active" : "")">
                    <button class="page-link" @onclick="@(() => GoToPage(page))">@page</button>
                </li>
            }
            <li class="page-item @(CurrentPage >= TotalPages ? "disabled" : "")">
                <button class="page-link" @onclick="@(() => GoToPage(CurrentPage + 1))" disabled="@(CurrentPage >= TotalPages)">
                    Next
                </button>
            </li>
        </ul>
    </nav>
}

@code {
    [Parameter] public int CurrentPage { get; set; } = 1;
    [Parameter] public int TotalPages { get; set; }
    [Parameter] public EventCallback<int> OnPageChanged { get; set; }

    private async Task GoToPage(int page)
    {
        if (page >= 1 && page <= TotalPages && page != CurrentPage)
        {
            await OnPageChanged.InvokeAsync(page);
        }
    }

    private IEnumerable<int> GetPageNumbers()
    {
        const int maxVisible = 5;
        int start = Math.Max(1, CurrentPage - maxVisible / 2);
        int end = Math.Min(TotalPages, start + maxVisible - 1);
        start = Math.Max(1, end - maxVisible + 1);

        for (int i = start; i <= end; i++)
            yield return i;
    }
}

@page "/catalog"
@namespace sv_494016ad00ea46c48391ee28b8b4cf4d.Components.Pages.Catalog
@rendermode InteractiveServer
@inject IProductService ProductService

<PageTitle>Product Catalog</PageTitle>

<h3 class="mb-3">Product Catalog</h3>

@if (errorMessage is not null)
{
    <div class="alert alert-danger">
        <strong>Error:</strong> @errorMessage
        <button class="btn btn-sm btn-outline-danger ms-2" @onclick="RetryLoad">Retry</button>
    </div>
}
else
{
    <div class="row">
        <div class="col-md-3">
            <CatalogSidebar Categories="categories" OnFilterApplied="HandleFilterApplied" />
        </div>
        <div class="col-md-9">
            @if (isLoading)
            {
                <div class="text-center py-5">
                    <div class="spinner-border text-primary" role="status">
                        <span class="visually-hidden">Loading…</span>
                    </div>
                    <p class="mt-2 text-muted">Loading products…</p>
                </div>
            }
            else
            {
                <CatalogToolbar SortBy="@sortBy"
                                Page="currentPage"
                                PageSize="pageSize"
                                TotalCount="totalCount"
                                OnSortChanged="HandleSortChanged" />

                <ProductGrid Products="products"
                             OnProductSelected="HandleProductSelected"
                             OnAddToCart="HandleAddToCart" />

                <CatalogPagination CurrentPage="currentPage"
                                   TotalPages="totalPages"
                                   OnPageChanged="HandlePageChanged" />
            }
        </div>
    </div>
}

@code {
    /// <summary>Raised when a product card is clicked so the parent can navigate to a detail page.</summary>
    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    private List<Product> products = new();
    private List<string> categories = new();
    private ProductFilter currentFilter = new(null, null, null, false);
    private string sortBy = "price_asc";
    private int currentPage = 1;
    private const int pageSize = 12;
    private int totalCount;
    private int totalPages;
    private bool isLoading = true;
    private string? errorMessage;

    protected override async Task OnInitializedAsync()
    {
        await LoadDataAsync();
    }

    private async Task LoadDataAsync()
    {
        try
        {
            isLoading = true;
            errorMessage = null;

            var categoriesTask = ProductService.GetCategoriesAsync();
            var productsTask = ProductService.SearchAsync(currentFilter, sortBy, currentPage, pageSize);
            await Task.WhenAll(categoriesTask, productsTask);

            categories = await categoriesTask;
            var result = await productsTask;
            ApplyResult(result);
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            isLoading = false;
        }
    }

    private async Task SearchAsync()
    {
        try
        {
            isLoading = true;
            errorMessage = null;
            var result = await ProductService.SearchAsync(currentFilter, sortBy, currentPage, pageSize);
            ApplyResult(result);
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            isLoading = false;
        }
    }

    private void ApplyResult(PagedResult<Product> result)
    {
        products = result.Items;
        totalCount = result.TotalCount;
        totalPages = (int)Math.Ceiling((double)result.TotalCount / pageSize);
    }

    private async Task HandleFilterApplied(ProductFilter filter)
    {
        currentFilter = filter;
        currentPage = 1;
        await SearchAsync();
    }

    private async Task HandleSortChanged(string newSort)
    {
        sortBy = newSort;
        currentPage = 1;
        await SearchAsync();
    }

    private async Task HandlePageChanged(int page)
    {
        currentPage = page;
        await SearchAsync();
    }

    private async Task HandleProductSelected(Product product)
    {
        await OnProductSelected.InvokeAsync(product);
    }

    private async Task HandleAddToCart(Product product)
    {
        // Placeholder for add-to-cart logic
    }

    private async Task RetryLoad() => await LoadDataAsync();
}

